import { useState } from 'react';

const [value, setValue] = useState(initialValue);
//     ↑               ↑                ↑
//   current         setter          used only
//   snapshot        function        on mount

// Called on every render (potentially slow)
const [settings, setSettings] = useState(JSON.parse(localStorage.getItem('settings') ?? '{}'));

// Called once — the function form
const [settings, setSettings] = useState(() => {
  const raw = localStorage.getItem('settings');
  return raw ? JSON.parse(raw) : {};
});

// BUG: both use the same stale `count` snapshot (e.g. 0)
// Result: count becomes 1, not 2
function handleDoubleIncrement() {
  setCount(count + 1); // schedules: set to 0+1=1
  setCount(count + 1); // schedules: set to 0+1=1  (same snapshot!)
}

// CORRECT: updater form uses the latest queued value
// Result: count becomes 2
function handleDoubleIncrement() {
  setCount(prev => prev + 1); // schedules: set to prev+1
  setCount(prev => prev + 1); // schedules: set to prev+1 (applied after the first)
}

function LoginForm() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [remember, setRemember] = useState(false);
  const [error, setError]       = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  async function handleSubmit(e) {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    try {
      await login({ email, password, remember });
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <form onSubmit={handleSubmit}>
      <input type="email" value={email} onChange={e => setEmail(e.target.value)} />
      <input type="password" value={password} onChange={e => setPassword(e.target.value)} />
      <label>
        <input type="checkbox" checked={remember} onChange={e => setRemember(e.target.checked)} />
        Remember me
      </label>
      {error && <p className="error">{error}</p>}
      <button disabled={isLoading}>{isLoading ? 'Logging in…' : 'Log in'}</button>
    </form>
  );
}

// WRONG: conditional useState breaks the call order
function BadComponent({ isAdmin }) {
  if (isAdmin) {
    const [role, setRole] = useState('admin'); // ← violates the rules
  }
  const [name, setName] = useState('');
  // ...
}

// CORRECT: declare all state at the top, conditionally use the values
function GoodComponent({ isAdmin }) {
  const [role, setRole] = useState('viewer'); // always called
  const [name, setName] = useState('');

  const displayRole = isAdmin ? 'admin' : role; // conditional logic outside state
  // ...
}

const [count, setCount] = useState(0);

// If count is already 0, calling setCount(0) is a no-op — no re-render
setCount(0);

// Primitives compare by value:
setCount(0);      // 0 === 0 → skip
setName('Alice'); // 'Alice' === 'Alice' → skip

// Objects and arrays compare by reference:
const sameRef = items;
setItems(sameRef);   // same reference → skip (mutation went unnoticed)

const newArray = [...items];
setItems(newArray);  // different reference → re-render even if contents are equal

// Inferred: string
const [name, setName] = useState('');
// setName('Alice') ✓    setName(42) ✗

// Inferred: number
const [count, setCount] = useState(0);

// Inferred too narrowly as `null`; provide explicit type for the union
const [user, setUser] = useState<User | null>(null);
// setUser({ id: 1, name: 'Alice' }) ✓    setUser(null) ✓

// Tuple: initial value is [], but items will be strings
const [tags, setTags] = useState<string[]>([]);

// Discriminated union — type must be declared explicitly
type Status = 'idle' | 'loading' | 'success' | 'error';
const [status, setStatus] = useState<Status>('idle');
// setStatus('loading') ✓    setStatus('unknown') ✗

// Three separate variables that always move together — verbose
const [x, setX] = useState(0);
const [y, setY] = useState(0);
const [dragging, setDragging] = useState(false);

// Group into one object — cleaner
const [pointer, setPointer] = useState({ x: 0, y: 0, dragging: false });

function handleMouseMove(e) {
  setPointer(prev => ({ ...prev, x: e.clientX, y: e.clientY }));
}

function handleMouseDown() {
  setPointer(prev => ({ ...prev, dragging: true }));
}

// useToggle.js
import { useState } from 'react';

export function useToggle(initial = false) {
  const [value, setValue] = useState(initial);
  const toggle = () => setValue(prev => !prev);
  return [value, toggle];
}

// Usage
function Modal() {
  const [isOpen, toggleOpen] = useToggle(false);
  return (
    <>
      <button onClick={toggleOpen}>Open</button>
      {isOpen && <dialog open>…<button onClick={toggleOpen}>Close</button></dialog>}
    </>
  );
}

import { useState } from 'react';

function NameForm() {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName]   = useState('');

  // Derived value — NOT a state variable
  const fullName = `${firstName} ${lastName}`.trim();

  return (
    <form>
      <input
        type="text"
        placeholder="First name"
        value={firstName}
        onChange={e => setFirstName(e.target.value)}
      />
      <input
        type="text"
        placeholder="Last name"
        value={lastName}
        onChange={e => setLastName(e.target.value)}
      />
      {fullName && <p>Hello, {fullName}!</p>}
    </form>
  );
}

// Object state for a form — fields update independently but submit together
const [form, setForm] = useState({
  email: '',
  password: '',
  rememberMe: false,
});

function handleChange(field) {
  return (e) => {
    const value = e.target.type === 'checkbox' ? e.target.checked : e.target.value;
    setForm(prev => ({ ...prev, [field]: value }));
  };
}

// Usage
<input value={form.email}    onChange={handleChange('email')} />
<input value={form.password} onChange={handleChange('password')} />
<input type="checkbox" checked={form.rememberMe} onChange={handleChange('rememberMe')} />

