import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import NameForm from './NameForm';

test('shows full name as the user types', async () => {
  render(<NameForm />);

  // Input driven by state — type into the field
  const firstInput = screen.getByPlaceholderText('First name');
  const lastInput  = screen.getByPlaceholderText('Last name');

  await userEvent.type(firstInput, 'Ada');
  await userEvent.type(lastInput, 'Lovelace');

  // Derived value displayed — assert the outcome
  expect(screen.getByText('Hello, Ada Lovelace!')).toBeInTheDocument();
});

test('starts with empty fields', () => {
  render(<NameForm />);
  expect(screen.queryByText(/Hello/)).not.toBeInTheDocument();
});
